// One-time migration: every existing ai_score in the DB was generated by the
// mock referee. Wipe them so the live UI shows "pending" instead of fake numbers.
// Re-running is idempotent.

const { db } = require('../src/db');

const result = db.prepare(`
  UPDATE submissions
  SET ai_score = NULL,
      ai_breakdown = ?
  WHERE ai_score IS NOT NULL OR ai_breakdown IS NOT NULL
`).run(JSON.stringify({
  status: 'pending',
  message: 'AI referee not yet wired — community vote is the live signal.',
}));

console.log(`Nullified ai_score on ${result.changes} submission(s).`);
